class_name Inventory
extends Resource
## иғҢеҢ…зі»з»ҹ вҖ” еҸҜеӯҳеӮЁд»»ж„Ҹ ItemData + ж•°йҮҸзҡ„зҪ‘ж ј

## иғҢеҢ…е®№йҮҸ
@export var capacity: int = 20

## зү©е“Ғж§ҪдҪҚж•°з»„пјҲзҙўеј• вҶ’ {item: ItemData, quantity: int}пјү
var _slots: Array[Dictionary] = []


func _init() -> void:
	_slots.resize(capacity)
	for i in range(capacity):
		_slots[i] = {"item": null, "quantity": 0}


## ж·»еҠ зү©е“ҒпјҲиҝ”еӣһжҲҗеҠҹж•°йҮҸпјҢ0=иғҢеҢ…ж»Ўпјү
func add_item(item: ItemData, quantity: int = 1) -> int:
	var added = 0
	var remaining = quantity

	# е…Ҳе°қиҜ•е ҶеҸ еҲ°е·Іжңүж§ҪдҪҚ
	if item.stackable:
		for i in range(capacity):
			var slot = _slots[i]
			if slot.item == item and slot.quantity < item.max_stack:
				var space = item.max_stack - slot.quantity
				var to_add = min(space, remaining)
				slot.quantity += to_add
				remaining -= to_add
				added += to_add
				if remaining <= 0:
					return added

	# еЎ«еҲ°з©әж§ҪдҪҚ
	for i in range(capacity):
		var slot = _slots[i]
		if slot.item == null:
			var to_add = min(item.max_stack if item.stackable else 1, remaining)
			slot.item = item
			slot.quantity = to_add
			remaining -= to_add
			added += to_add
			if remaining <= 0:
				return added

	return added


## з§»йҷӨзү©е“Ғ
func remove_item(item: ItemData, quantity: int = 1) -> int:
	var removed = 0
	for i in range(capacity - 1, -1, -1):
		var slot = _slots[i]
		if slot.item == item:
			var to_remove = min(quantity - removed, slot.quantity)
			slot.quantity -= to_remove
			removed += to_remove
			if slot.quantity <= 0:
				slot.item = null
				slot.quantity = 0
			if removed >= quantity:
				return removed
	return removed


## иҺ·еҸ–жҢҮе®ҡж§ҪдҪҚ
func get_slot(index: int) -> Dictionary:
	if index >= 0 and index < capacity:
		return _slots[index]
	return {"item": null, "quantity": 0}


## иҺ·еҸ–зү©е“ҒжҖ»ж•°йҮҸ
func get_item_count(item: ItemData) -> int:
	var count = 0
	for slot in _slots:
		if slot.item == item:
			count += slot.quantity
	return count


## жҳҜеҗҰжңүи¶іеӨҹз©әй—ҙ
func has_space(item: ItemData, quantity: int = 1) -> bool:
	var space = 0
	if item.stackable:
		for slot in _slots:
			if slot.item == item:
				space += item.max_stack - slot.quantity
	for slot in _slots:
		if slot.item == null:
			space += item.max_stack if item.stackable else 1
	return space >= quantity

