extends CanvasLayer
## иғҢеҢ…+зәёеЁғеЁғиЈ…еӨҮ йӣҶжҲҗйқўжқҝ вҖ” I й”®еҲҮжҚў

@export var columns: int = 5

var inventory: Inventory
