class_name BuffManager
extends Node
## Buff з®ЎзҗҶеҷЁ вҖ” жҢӮиҪҪеҲ° Player иҠӮзӮ№пјҢз®ЎзҗҶжүҖжңүжҝҖжҙ»зҡ„ Buff
##
## иЈ…еӨҮгҖҒжҠҖиғҪгҖҒж¶ҲиҖ—е“Ғзӯүд»»дҪ•зі»з»ҹйғҪйҖҡиҝҮ BuffManager ж–ҪеҠ /з§»йҷӨж•Ҳжһң

## еҪ“еүҚжҝҖжҙ»зҡ„жүҖжңү Buff
var _active_buffs: Array[Buff] = []

## е®ҡж—¶еҷЁеј•з”Ё
var _tick_timer: float = 0.0


func _process(delta: float) -> void:
	if _active_buffs.is_empty():
		return
	_tick_timer += delta
	if _tick_timer >= 1.0:
		_tick_timer -= 1.0
		_tick_buffs()


func _tick_buffs() -> void:
	var entity = get_parent()
	for buff in _active_buffs:
		if buff.tick_interval > 0 and buff.tick_heal > 0:
			if entity.has_method("heal"):
				entity.heal(buff.tick_heal)


## ж–ҪеҠ  BuffпјҲиЈ…еӨҮгҖҒжҠҖиғҪзӯүи°ғз”Ёпјү
func apply_buff(buff: Buff) -> void:
	if not buff:
		return
	buff.apply_to(get_parent())
	_active_buffs.append(buff)
	print("рҹҹў BuffManager: ж–ҪеҠ  %s" % buff.display_name)


## з§»йҷӨ Buff
func remove_buff(buff: Buff) -> void:
	if not buff or not buff in _active_buffs:
		return
	buff.remove_from(get_parent())
	_active_buffs.erase(buff)
	print("рҹ”ҙ BuffManager: з§»йҷӨ %s" % buff.display_name)


## з§»йҷӨжүҖжңү BuffпјҲжӯ»дәЎ/йҮҚзҪ®ж—¶пјү
func clear_all() -> void:
	for buff in _active_buffs:
		buff.remove_from(get_parent())
	_active_buffs.clear()

