class_name Buff
extends Resource
## Buff/иў«еҠЁж•Ҳжһң вҖ” еҸҜиў«иЈ…еӨҮгҖҒжҠҖиғҪгҖҒж¶ҲиҖ—е“Ғзӯүд»»дҪ•зі»з»ҹеӨҚз”Ё
##
## duration = 0 иЎЁзӨәж°ёд№…пјҲиЈ…еӨҮзұ» Buffпјү
## tick_interval = 0 иЎЁзӨәдёҚи§ҰеҸ‘ tick

## жҳҫзӨәеҗҚз§°
@export var display_name: String = ""

## еӣҫж Ү
@export var icon: Texture2D

## жҢҒз»ӯж—¶й—ҙпјҲз§’пјҢ0=ж°ёд№…пјү
@export var duration: float = 0.0

## tick й—ҙйҡ”пјҲз§’пјҢ0=дёҚи§ҰеҸ‘пјү
@export var tick_interval: float = 0.0

## еұһжҖ§еҠ жҲҗпјҲеӣәе®ҡеҖјпјү
@export var stat_modifiers: Dictionary = {}

## еұһжҖ§зҷҫеҲҶжҜ”еҠ жҲҗ
@export var stat_multipliers: Dictionary = {}

## tick ж—¶еӣһеӨҚ HP
@export var tick_heal: int = 0


## еә”з”ЁжӯӨ Buff еҲ°зӣ®ж Үе®һдҪ“
func apply_to(entity: Node) -> void:
	if not entity:
		return
	for stat in stat_modifiers:
		_apply_stat(entity, stat, stat_modifiers[stat])


## д»Һзӣ®ж Үе®һдҪ“з§»йҷӨжӯӨ Buff
func remove_from(entity: Node) -> void:
	if not entity:
		return
	for stat in stat_modifiers:
		_apply_stat(entity, stat, -stat_modifiers[stat])


## еә”з”ЁеҚ•дёӘеұһжҖ§дҝ®ж”№
func _apply_stat(entity: Node, stat: String, amount: float) -> void:
	if stat in entity:
		entity.set(stat, entity.get(stat) + amount)

